1	import { useState } from "react";
2	import { View, Text, Input, Textarea, Picker } from "@tarojs/components";
3	import Taro, { useDidShow } from "@tarojs/taro";
4	import { apiFetch, PRESET_DOMAINS } from "../../lib";
5	import ReminderCard from "../../components/reminder-card";
6	import "./index.scss";
7	
8	export default function ProfilePage() {
9	  const [profile, setProfile] = useState({
10	    name: "", goals: "", wakeTime: "07:00", sleepTime: "23:00", customPrompt: "",
11	  });
12	  const [inputs, setInputs] = useState<{ category: string; content: string }[]>([]);
13	  const [newInput, setNewInput] = useState({ category: "健身", content: "" });
14	  const [saved, setSaved] = useState(false);
15	  const [reminderEnabled, setReminderEnabled] = useState(false);
16	  const [reminderTime, setReminderTime] = useState("21:00");
17	  const [reminderDays, setReminderDays] = useState<number[]>([1, 2, 3, 4, 5, 6, 7]);
18	
19	  useDidShow(() => {
20	    apiFetch("/api/profile").then((data) => {
21	      if (data.profile) {
22	        setProfile({
23	          name: data.profile.name || "",
24	          goals: Array.isArray(data.profile.goals) ? data.profile.goals.join("\n") : "",
25	          wakeTime: data.profile.wakeTime || "07:00",
26	          sleepTime: data.profile.sleepTime || "23:00",
27	          customPrompt: data.profile.preferences?.customPrompt || "",
28	        });
29	        const reminder = data.profile.reminder || {};
30	        setReminderEnabled(reminder.enabled || false);
31	        setReminderTime(reminder.time || "21:00");
32	        setReminderDays(reminder.days || [1, 2, 3, 4, 5, 6, 7]);
33	      }
34	      if (data.inputs) setInputs(data.inputs);
35	    });
36	  });
37	
38	  async function saveProfile() {
39	    await apiFetch("/api/profile", {
40	      method: "POST",
41	      body: JSON.stringify({
42	        name: profile.name,
43	        goals: profile.goals.split("\n").filter((g) => g.trim()),
44	        wakeTime: profile.wakeTime,
45	        sleepTime: profile.sleepTime,
46	        customPrompt: profile.customPrompt,
47	      }),
48	    });
49	    setSaved(true);
50	    setTimeout(() => setSaved(false), 2000);
51	  }
52	
53	  const REMINDER_TEMPLATE_ID = "TEMPLATE_ID";
54	
55	  async function saveReminder(enabled: boolean, time: string, days: number[]) {
56	    try {
57	      await apiFetch("/api/profile", {
58	        method: "POST",
59	        body: JSON.stringify({ reminder: { enabled, time, days } }),
60	      });
61	    } catch (e) {
62	      Taro.showToast({ title: "保存失败，请稍后重试", icon: "none" });
63	      throw e;
64	    }
65	  }
66	
67	  async function handleReminderToggle(value: boolean) {
68	    if (value) {
69	      try {
70	        const res: Record<string, string> = await (Taro as any).requestSubscribeMessage({
71	          tmplIds: [REMINDER_TEMPLATE_ID],
72	        });
73	        if (res[REMINDER_TEMPLATE_ID] !== "accept") {
74	          Taro.showToast({ title: "需要授权才能开启每日提醒", icon: "none" });
75	          return;
76	        }
77	      } catch {
78	        Taro.showToast({ title: "授权失败，请稍后重试", icon: "none" });
79	        return;
80	      }
81	    }
82	    await saveReminder(value, reminderTime, reminderDays);
83	    setReminderEnabled(value);
84	    Taro.showToast({
85	      title: value ? "每日提醒已开启" : "每日提醒已关闭",
86	      icon: "success",
87	    });
88	  }
89	
90	  async function handleReminderTimeChange(time: string) {
91	    if (reminderEnabled) {
92	      await saveReminder(true, time, reminderDays);
93	    }
94	    setReminderTime(time);
95	  }
96	
97	  async function handleReminderDayToggle(day: number) {
98	    const newDays = reminderDays.includes(day)
99	      ? reminderDays.filter((d) => d !== day)
100	      : [...reminderDays, day];
101	    if (newDays.length === 0) return;
102	    if (reminderEnabled) {
103	      await saveReminder(true, reminderTime, newDays);
104	    }
105	    setReminderDays(newDays);
106	  }
107	
108	  async function addInput() {
109	    if (!newInput.content.trim()) return;
110	    await apiFetch("/api/profile/input", {
111	      method: "POST",
112	      body: JSON.stringify(newInput),
113	    });
114	    setInputs([...inputs, newInput]);
115	    setNewInput({ category: "健身", content: "" });
116	  }
117	
118	  return (
119	    <View className="page">
120	      <Text className="page-title">个人设置</Text>
121	      <Text className="page-subtitle">越了解你，越能精准辅助</Text>
122	
123	      <View className="card">
124	        <Text className="card-title">基本信息</Text>
125	        <View className="form-group">
126	          <Text className="form-label">你的名字/称号</Text>
127	          <Input className="form-input" placeholder="朕 / 陛下" value={profile.name} onInput={(e) => setProfile({ ...profile, name: e.detail.value })} />
128	        </View>
129	        <View className="form-row">
130	          <View className="form-group flex-1">
131	            <Text className="form-label">起床时间</Text>
132	            <Picker mode="time" value={profile.wakeTime} onChange={(e) => setProfile({ ...profile, wakeTime: e.detail.value })}>
133	              <View className="form-input" style={{ display: "flex", alignItems: "center" }}><Text>{profile.wakeTime}</Text></View>
134	            </Picker>
135	          </View>
136	          <View className="form-group flex-1">
137	            <Text className="form-label">睡觉时间</Text>
138	            <Picker mode="time" value={profile.sleepTime} onChange={(e) => setProfile({ ...profile, sleepTime: e.detail.value })}>
139	              <View className="form-input" style={{ display: "flex", alignItems: "center" }}><Text>{profile.sleepTime}</Text></View>
140	            </Picker>
141	          </View>
142	        </View>
143	      </View>
144	
145	      <View className="card">
146	        <Text className="card-title">你的目标</Text>
147	        <Textarea className="form-textarea" placeholder={"提升商业分析能力\n养成运动习惯\n扩大社交圈\n..."} value={profile.goals} onInput={(e) => setProfile({ ...profile, goals: e.detail.value })} />
148	      </View>
149	
150	      <View className="card">
151	        <Text className="card-title">AI 个性化提示词</Text>
152	        <Textarea className="form-textarea" placeholder={"用「陛下」称呼我\n关注商业和管理领域\n多推荐前沿科技内容"} value={profile.customPrompt} onInput={(e) => setProfile({ ...profile, customPrompt: e.detail.value })} />
153	      </View>
154	
155	      <View className="save-btn" onClick={saveProfile}>
156	        <Text>{saved ? "已保存 ✓" : "保存设置"}</Text>
157	      </View>
158	
159	      <ReminderCard
160	        enabled={reminderEnabled}
161	        time={reminderTime}
162	        days={reminderDays}
163	        onToggle={handleReminderToggle}
164	        onTimeChange={handleReminderTimeChange}
165	        onDayToggle={handleReminderDayToggle}
166	      />
167	
168	      <View className="card">
169	        <Text className="card-title">个性化需求</Text>
170	        <View style={{ marginBottom: "20rpx" }}>
171	          {inputs.map((pi, i) => (
172	            <Text key={i} className="input-tag">{pi.category}: {pi.content}</Text>
173	          ))}
174	        </View>
175	        <View className="input-row">
176	          <Picker mode="selector" range={PRESET_DOMAINS.map(d => d.name)} value={PRESET_DOMAINS.findIndex(d => d.name === newInput.category)} onChange={(e) => setNewInput({ ...newInput, category: PRESET_DOMAINS[+e.detail.value].name })}>
177	            <View className="form-input" style={{ width: "160rpx", display: "flex", alignItems: "center" }}><Text>{newInput.category}</Text></View>
178	          </Picker>
179	          <Input className="form-input" style={{ flex: 1 }} placeholder="描述你的个性化需求..." value={newInput.content} onInput={(e) => setNewInput({ ...newInput, content: e.detail.value })} onConfirm={addInput} />
180	          <Text className="add-btn" onClick={addInput}>添加</Text>
181	        </View>
182	      </View>
183	    </View>
184	  );
185	}
