```ts
function countWeekdays(days: number): number {
  let count = 0;
  const now = new Date();
  for (let i = 0; i < days; i++) {
    const d = new Date(now);
    d.setDate(d.getDate() - i);
    const day = d.getDay();
    if (day >= 1 && day <= 5) count++;
  }
  return count;
}
```

